const express = require('express');

function createApp() {
  const app = express();

  app.get('/users/:id', (req, res) => {
    res.json({ id: req.params.id });
  });

  app.get('/search', (req, res) => {
    res.json({ query: req.query.q });
  });

  return app;
}

module.exports = { createApp };
